const modules = moduleTopics.map((topic, index) => {
  const module = baseModule(topic, index);
  const extra = content[index];

  return extra
    ? {
        ...module,
        ...extra,
        id: module.id,
        title: module.title,
        topic: module.topic,
        color: module.color,
        softColor: module.softColor
      }
    : module;
});
